'use client';
// TODO: сделать SSR, а не client
import { useAds } from '@/entities/ad/api/useAds';

export default function Page() {
  const { data, isLoading } = useAds({
    page: 1,
    limit: 10,
  });
  if (isLoading) return <div>Loading...</div>;
  return (
    <div>
      {/* TODO: типизировать data */}
      {data.items.map((ad: { id: string; title: string; price: number }) => (
        <div key={ad.id}>
          <h3>{ad.title}</h3>
          <p>{ad.price}</p>
        </div>
      ))}
    </div>
  );
}
